#include <hexi/static_buffer.h>

template<size_t buffer_size = 1024>
struct BufferInfo {
    size_t capacity;
    size_t current_size;
    size_t free_space;
};

BufferInfo<> get_buffer_info(const hexi::static_buffer<std::byte, 1024>& buffer) {
    BufferInfo<> info;

    // Get total capacity using capacity() member function
    info.capacity = buffer.capacity();

    // Get current readable data size using size() member function
    info.current_size = buffer.size();

    // Calculate free space as capacity minus current size
    info.free_space = buffer.capacity() - buffer.size();

    return info;
}
```

