struct MeasurementData {
    uint32_t sensor_id;
    std::vector<float> temperatures;
    double pressure;

    void serialise(auto& adaptor) const {
        // Serialization: write sensor_id directly
        adaptor.write(sensor_id);

        // Convert and write temperatures
        for (float temp : temperatures) {
            float converted = temp;
            hexi::endian::conditional_reverse_inplace(converted, std::endian::native, std::endian::little);
            adaptor.write(converted);
        }

        // Convert and write pressure
        double converted_pressure = pressure;
        hexi::endian::conditional_reverse_inplace(converted_pressure, std::endian::native, std::endian::little);
        adaptor.write(converted_pressure);
    }

    void serialise(auto& adaptor) {
        // Deserialization: read sensor_id directly
        adaptor.read(&sensor_id);

        // Read and convert temperatures
        uint32_t temp_count;
        adaptor.read(&temp_count);
        temperatures.resize(temp_count);
        for (uint32_t i = 0; i < temp_count; ++i) {
            float& temp = temperatures[i];
            adaptor.read(&temp);
            hexi::endian::little_to_native_inplace(temp);
        }

        // Read and convert pressure
        adaptor.read(&pressure);
        hexi::endian::little_to_native_inplace(pressure);
    }
};

std::vector<uint8_t> serialize_measurement_data(const MeasurementData& data) {
    std::vector<uint8_t> buffer;
    hexi::buffer_adaptor adaptor(buffer);
    adaptor.serialise(data);
    return buffer;
}

MeasurementData deserialize_measurement_data(const std::span<const uint8_t> buffer) {
    std::vector<uint8_t> temp_buffer(buffer.begin(), buffer.end());
    hexi::buffer_adaptor adaptor(temp_buffer);
    MeasurementData data;
    adaptor.deserialise(data);
    return data;
}

struct SensorInfo {
    uint32_t sensor_id;
    std::string_view sensor_name;
};

SensorInfo extract_sensor_info(const std::span<const uint8_t> buffer) {
    std::vector<uint8_t> temp_buffer(buffer.begin(), buffer.end());
    hexi::buffer_adaptor adaptor(temp_buffer);

    // Extract sensor name using view
    std::string_view sensor_name = adaptor.view();

    // Check bounds before reading sensor_id
    if (adaptor.total_read() + sizeof(uint32_t) > adaptor.size()) {
        return SensorInfo{0, ""};
    }

    // Read sensor_id
    uint32_t sensor_id;
    adaptor.read(&sensor_id);

    // Skip remaining data
